import React from 'react';
import '../styles/components/Contact.css';

function Contact() {
  const socialMedia = [
    {
      name: 'LinkedIn',
      icon: '💼',
      username: '@yourname',
      url: 'https://linkedin.com/in/yourprofile'
    },
    {
      name: 'Instagram',
      icon: '📷',
      username: '@yourname',
      url: 'https://instagram.com/yourname'
    },
    {
      name: 'WhatsApp',
      icon: '💬',
      username: '+62 xxx',
      url: 'https://wa.me/62xxxxxxxxx'
    }
  ];

  return (
    <section id="contact" className="contact">
      <div className="container">
        <h2 className="section-title">Get In Touch</h2>
        
        <div className="contact-content">
          <div className="contact-intro">
            <h3>Let's Connect!</h3>
            <p>
              Feel free to reach out through any of these platforms. 
              I'm always open to discussing new projects, opportunities, or just having a chat!
            </p>
          </div>
          
          <div className="social-links">
            {socialMedia.map((social, index) => (
              <a 
                key={index}
                href={social.url} 
                target="_blank" 
                rel="noopener noreferrer"
                className="social-link"
              >
                <span className="social-icon">{social.icon}</span>
                <span className="social-label">{social.name}</span>
                <span className="social-username">{social.username}</span>
              </a>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

export default Contact;
